export type Verdict = "verified" | "contradicted" | "unverified";
export type EvidenceQuality = "high" | "medium" | "low";
export type TalentEvidence = { note: string; url: string; source_type: string };
export type TalentClaim = { claim: string; verdict: Verdict; evidence: TalentEvidence[] };
export type TalentSearchBrief = { original_query: string; target_directions: string[]; required_skills: string[]; preferred_skills: string[]; seniority: string | null; geography: string | null; evidence_preferences: string[]; exclusions: string[] };
export type SearchPlanSourceStrategy = { source_type: string; target: string; reason: string; coverage_group: string; query: string };
export type SearchPlanAdjacentPool = { pool: string; reason: string };
export type TalentSearchPlan = { must_have: string[]; nice_to_have: string[]; exclusions: string[]; source_strategy: SearchPlanSourceStrategy[]; adjacent_pools: SearchPlanAdjacentPool[] };
export type SourceExecutionStatus = "planned" | "completed" | "partial" | "failed";
export type SourceExecutionJob = { job_id: string; source_type: string; coverage_group: string; query: string; status: SourceExecutionStatus; urls_found: number; evidence_found: number; candidate_leads: string[]; source_urls: string[]; error: string; next_action: string };
export type SourceExecution = { summary: string; jobs: SourceExecutionJob[] };
export type CoverageBackfillStatus = "planned" | "completed" | "skipped";
export type CoverageBackfillJob = { gap_id: string; coverage_group: string; missing_source_type: string; query: string; reason: string; priority: number; status: CoverageBackfillStatus; candidate_names: string[]; source_types_to_check: string[] };
export type CoverageBackfillPlan = { summary: string; jobs: CoverageBackfillJob[] };
export type EvidenceGraphSourceMix = { source_type: string; count: number };
export type EvidenceGraphCandidate = { candidate_name: string; independent_sources: number; source_types: string[]; strongest_evidence: string[]; weakest_evidence: string[]; cross_validation: string; risk_flags: string[] };
export type TalentEvidenceGraph = { summary: string; source_mix: EvidenceGraphSourceMix[]; candidates: EvidenceGraphCandidate[] };
export type TalentMapItem = { direction: string; fit: string; candidate_count: number; rationale: string };
export type ScoreBreakdown = { achievement_signals: number; skill_match: number; work_history: number; evidence_quality: number };
export type EvidenceAudit = { verified_claims: string[]; unverified_claims: string[]; contradicted_claims: string[]; single_source_claims: string[]; identity_risks: string[]; recency_notes: string[]; overall_evidence_quality: EvidenceQuality };
export type TalentCandidate = { name: string; headline: string; location: string | null; current_role: string | null; current_company: string | null; ai_directions: string[]; match_score: number; score_breakdown: ScoreBreakdown; strongest_signals: string[]; uncertainties: string[]; links: { github: string | null; linkedin: string | null; scholar: string | null; huggingface: string | null; website: string | null; other: string | null }; claims: TalentClaim[]; evidence_audit: EvidenceAudit; outreach_angle: string; summary: string };
export type TalentSearchResult = { search_brief: TalentSearchBrief; search_plan: TalentSearchPlan; source_execution: SourceExecution; coverage_backfill: CoverageBackfillPlan; evidence_graph: TalentEvidenceGraph; talent_map: TalentMapItem[]; candidates: TalentCandidate[] };
export type EditableSearchPlanDraft = TalentSearchResult;
export type EvidenceCoverageGroup = { key: string; label: string; count: number; source_types: string[]; missing_source_types: string[]; status: "covered" | "missing" };
export type SourceQueryPlanItem = { source_type: string; coverage_group: string; target: string; query: string; reason: string; priority: number };
export type CandidateComparisonRow = { name: string; role: string; primary_direction: string; secondary_directions: string; match_score: number; achievement_signals: number; skill_match: number; work_history: number; evidence_score: number; evidence_quality: string; independent_sources: number; source_types: string; coverage_gaps: string; top_signal: string; risk_summary: string };
export type CandidateEvidenceAuditSummary = { candidate_name: string; overall_evidence_quality: EvidenceQuality; independent_sources: number; source_types: string[]; verified_count: number; unverified_count: number; contradicted_count: number; verified_claims: string[]; unverified_claims: string[]; contradicted_claims: string[]; single_source_claims: string[]; identity_risks: string[]; recency_notes: string[]; cross_validation: string; strongest_evidence: string[]; weakest_evidence: string[]; risk_flags: string[] };
export type CandidateReadingSummary = { title: string; sections: Array<{ key: string; label: string; body: string }> };
export type CandidateEvidenceDossierGroup = { key: string; label: string; status: "covered" | "missing"; source_types: string[]; missing_source_types: string[]; claim_count: number; evidence_count: number; primary_claims: string[] };
export type CandidateBackfillDelta = { title: string; merged_at: string; new_evidence_count: number; new_source_types: string[]; new_evidence_urls: string[]; merge_note: string };
export type CandidateEvidenceDossier = { title: string; conclusion: string; risk_summary: string; verdict_summary: string; metrics: Array<{ label: string; value: string }>; source_types: string[]; primary_evidence: string[]; weak_evidence: string[]; evidence_groups: CandidateEvidenceDossierGroup[]; verification_gaps: string[]; backfill_jobs: CoverageBackfillJob[]; backfill_delta: CandidateBackfillDelta | null };
export type CandidateEvidenceMatrixSource = { note: string; url: string; host: string; source_type: string };
export type CandidateEvidenceMatrixRow = { key: string; claim: string; verdict: Verdict; verdict_label: string; evidence_count: number; source_types: string[]; sources: CandidateEvidenceMatrixSource[]; risk_label: string };
export type CandidateEvidenceMatrix = { title: string; description: string; summary: { verified: number; unverified: number; contradicted: number; no_source: number; single_source: number }; rows: CandidateEvidenceMatrixRow[]; empty: boolean };
export type ShortlistDeliveryCandidate = { name: string; role: string; match_score: number; evidence_quality: EvidenceQuality; independent_sources: number; recommendation_reason: string; primary_risk: string };
export type ShortlistDeliveryReport = { brief_summary: string; candidate_count: number; strong_recommendation_count: number; average_match_score: number; high_evidence_count: number; covered_group_count: number; coverage_group_count: number; coverage_summary: Array<{ key: string; label: string; status: string; count: number; source_types: string[]; missing_source_types: string[] }>; recommended_candidates: ShortlistDeliveryCandidate[]; report_risks: string[]; next_steps: string[] };
export type BackfillMergeCandidate = { candidate_name: string; new_evidence_count: number; new_source_types: string[]; new_evidence_urls: string[]; merge_note: string };
export type BackfillCoverageGain = { key: string; label: string; before_count: number; after_count: number; added_source_types: string[] };
export type BackfillMergeSummary = { summary: string; improved_candidates: BackfillMergeCandidate[]; new_candidate_names: string[]; coverage_gains: BackfillCoverageGain[] };
export type BackfillMergedTalentSearchResult = TalentSearchResult & { backfill_merge: { merged_at: string; summary: BackfillMergeSummary } };
export type SearchFeedbackPrecision = "accurate" | "partial" | "off";
export type SearchFeedbackSatisfaction = "satisfied" | "mixed" | "unsatisfied";
export type SearchFeedbackIssue = "too_broad" | "wrong_seniority" | "wrong_direction" | "weak_evidence" | "wrong_location" | "too_few" | "too_many" | "other";
export type SearchFeedbackFocus = "stricter_match" | "expand_sources" | "stronger_evidence" | "adjacent_pools" | "higher_seniority" | "location_fit";
export type SearchFeedback = { precision?: SearchFeedbackPrecision | ""; satisfaction?: SearchFeedbackSatisfaction | ""; issue?: SearchFeedbackIssue | ""; focus?: SearchFeedbackFocus | "" };
export const AI_DIRECTIONS: string[];
export const VERDICTS: Verdict[];
export const EVIDENCE_QUALITY: EvidenceQuality[];
export const EVIDENCE_COVERAGE_GROUPS: { key: string; label: string; source_types: string[] }[];
export const SOURCE_EXECUTION_STATUSES: SourceExecutionStatus[];
export const COVERAGE_BACKFILL_STATUSES: CoverageBackfillStatus[];
export function normalizeTalentSearchResult(data: unknown): TalentSearchResult;
export function buildCandidateComparisonRows(result: unknown): CandidateComparisonRow[];
export function buildCandidateEvidenceAudit(input?: { result?: unknown; candidate?: unknown }): CandidateEvidenceAuditSummary;
export function buildCandidateReadingSummary(input?: { result?: unknown; candidate?: unknown; locale?: "zh" | "en" }): CandidateReadingSummary;
export function buildCandidateEvidenceDossier(input?: { result?: unknown; candidate?: unknown; locale?: "zh" | "en" }): CandidateEvidenceDossier;
export function buildCandidateEvidenceMatrix(input?: { result?: unknown; candidate?: unknown; locale?: "zh" | "en" }): CandidateEvidenceMatrix;
export function buildShortlistDeliveryReport(result: unknown, options?: { locale?: "zh" | "en" | string }): ShortlistDeliveryReport;
export function buildCoverageBackfillPlan(result: unknown, options?: { locale?: "zh" | "en" | string }): CoverageBackfillPlan;
export function buildBackfillSearchInput(input?: { job?: unknown; originalQuery?: string; locale?: "zh" | "en" | string }): string;
export function buildBackfillMergeSummary(input?: { originalResult?: unknown; backfillResult?: unknown; locale?: "zh" | "en" | string }): BackfillMergeSummary;
export function mergeBackfillResult(input?: { originalResult?: unknown; backfillResult?: unknown; mergedAt?: string; locale?: "zh" | "en" | string }): BackfillMergedTalentSearchResult;
export function buildEditableSearchPlanDraft(query: unknown, options?: { locale?: "zh" | "en" | string }): EditableSearchPlanDraft;
export function buildSearchInputFromEditablePlan(input?: { draft?: unknown }): string;
export function buildFeedbackOptimizedSearchInput(input?: { result?: unknown; feedback?: SearchFeedback }): string;
export function buildEvidenceCoverage(result: unknown): EvidenceCoverageGroup[];
export function buildSourceQueryPlan(result: unknown): SourceQueryPlanItem[];
export function buildSourceExecution(result: unknown): SourceExecution;
export function isTalentSearchResult(data: unknown): data is TalentSearchResult;
export function isSearchUrl(url: unknown): boolean;
